/* =============================================================================
 * main.c - AHRS HW trajektorija za vizualizaciju (sa Euler uglovima na uredjaju)
 *           Puni dataset (1918 sample-ova iz data1504.csv)
 *
 * Output u PuTTY: CSV format spreman za visualize_motion.py
 *   time,qw,qx,qy,qz,roll,pitch,yaw
 *
 * BITNO: Vitis project mora da linkuje -lm (videti uputstvo).
 *
 * Workflow:
 *   1. PuTTY logging -> putty.log
 *   2. Pokreni aplikaciju (~25s)
 *   3. Izoluj redove izmedju BEGIN_CSV i END_CSV markera
 *   4. Sacuvaj kao hw_orientation.csv
 *   5. python3 visualize_motion.py hw_orientation.csv
 * =============================================================================
 */

