/* ---------- Stampanje float-a ---------- */
static void pf(float v) {
    if (v < 0.0f) { xil_printf("-"); v = -v; }
    int   whole = (int)v;
    float fpart = (v - (float)whole) * 1000000.0f;
    int   frac  = (int)(fpart + 0.5f);
    if (frac >= 1000000) { whole += 1; frac -= 1000000; }
    xil_printf("%d.%06d", whole, frac);
}

/* ---------- Fast inverse square root ---------- */
static inline float fast_inv_sqrt(float x) {
    union { float f; int32_t i; } u;
    u.f = x;
    u.i = 0x5F1F1412 - (u.i >> 1);
    return u.f * (1.69000231f - 0.714158168f * x * u.f * u.f);
}

/* ---------- Float -> fixed-point konverzije za IP ---------- */
static inline uint32_t flt2u32(float f) {
    union { float f; uint32_t u; } u; u.f = f; return u.u;
}
static inline uint32_t flt_to_q9_7(float f) {
    if (f >  255.99f) f =  255.99f;   /* <-- DODAJ */
    if (f < -256.0f)  f = -256.0f;    /* <-- DODAJ */
    int32_t i = (int32_t)(f * 128.0f);
    return (uint32_t)i & 0xFFFFU;
}
static inline uint32_t flt_to_q4_16(float f) {
    uint32_t u = (uint32_t)(f * 65536.0f);
    return u & 0xFFFFFU;
}
static inline uint32_t flt_to_q0_20(float f) {
    uint32_t u = (uint32_t)(f * 1048576.0f);
    return u & 0xFFFFFU;
}
static inline float q1_30_to_flt(uint32_t u) {
    /* 32-bit signed Q1.30: LSB = 2^-30, range ±2 */
    return (float)((int32_t)u) / 1073741824.0f;  /* 2^30 = 1073741824 */
}
static inline float q2_24_to_flt(uint32_t u) {
    return (float)((int32_t)u) / 16777216.0f;
}
static inline uint32_t flt_to_q1_30(float f) {
    /* 32-bit signed Q1.30: max ±2, sa saturacijom */
    if (f >  1.999999f) f =  1.999999f;
    if (f < -2.0f)      f = -2.0f;
    int32_t i = (int32_t)(f * 1073741824.0f);  /* 2^30 */
    return (uint32_t)i;
}

/* ---------- HW poziv ---------- */
static int hw_sec5to8(
    float qw, float qx, float qy, float qz,
    float gx, float gy, float gz,
    float ax, float ay, float az,
    float hgx, float hgy, float hgz,
    float dt, float gain,
    float *nqw, float *nqx, float *nqy, float *nqz,
    float *hfbx_out, float *hfby_out, float *hfbz_out)
{
    Xil_Out32(BRAM_IN_BYTE +  0U * 4U, flt_to_q9_7(gx));
    Xil_Out32(BRAM_IN_BYTE +  1U * 4U, flt_to_q9_7(gy));
    Xil_Out32(BRAM_IN_BYTE +  2U * 4U, flt_to_q9_7(gz));
    Xil_Out32(BRAM_IN_BYTE +  3U * 4U, flt2u32(ax));
    Xil_Out32(BRAM_IN_BYTE +  4U * 4U, flt2u32(ay));
    Xil_Out32(BRAM_IN_BYTE +  5U * 4U, flt2u32(az));
    Xil_Out32(BRAM_IN_BYTE +  6U * 4U, flt2u32(hgx));
    Xil_Out32(BRAM_IN_BYTE +  7U * 4U, flt2u32(hgy));
    Xil_Out32(BRAM_IN_BYTE +  8U * 4U, flt2u32(hgz));
    Xil_Out32(BRAM_IN_BYTE +  9U * 4U, flt_to_q0_20(dt));
    Xil_Out32(BRAM_IN_BYTE + 10U * 4U, flt_to_q4_16(gain));
    Xil_Out32(BRAM_IN_BYTE + 11U * 4U, flt_to_q1_30(qw));
    Xil_Out32(BRAM_IN_BYTE + 12U * 4U, flt_to_q1_30(qx));
    Xil_Out32(BRAM_IN_BYTE + 13U * 4U, flt_to_q1_30(qy));
    Xil_Out32(BRAM_IN_BYTE + 14U * 4U, flt_to_q1_30(qz));

    Xil_Out32(AHRS_CTRL, 0x1U);

    int timeout = 1000000;
    while (timeout-- > 0) {
        if (Xil_In32(AHRS_STATUS) & STATUS_DONE) break;
    }
    if (timeout <= 0) return -1;

    uint32_t r0 = Xil_In32(BRAM_OUT_BYTE + 0U * 4U);
    uint32_t r1 = Xil_In32(BRAM_OUT_BYTE + 1U * 4U);
    uint32_t r2 = Xil_In32(BRAM_OUT_BYTE + 2U * 4U);
    uint32_t r3 = Xil_In32(BRAM_OUT_BYTE + 3U * 4U);
    uint32_t r4 = Xil_In32(BRAM_OUT_BYTE + 4U * 4U);
    uint32_t r5 = Xil_In32(BRAM_OUT_BYTE + 5U * 4U);
    uint32_t r6 = Xil_In32(BRAM_OUT_BYTE + 6U * 4U);

    *nqw = q1_30_to_flt(r0);
    *nqx = q1_30_to_flt(r1);
    *nqy = q1_30_to_flt(r2);
    *nqz = q1_30_to_flt(r3);
    *hfbx_out = q2_24_to_flt(r4);
    *hfby_out = q2_24_to_flt(r5);
    *hfbz_out = q2_24_to_flt(r6);
     return 0;
}

/* ---------- Kvaternion -> Euler uglovi (ZYX konvencija, u stepenima) ---------- */
static void quat_to_euler_deg(
    float qw, float qx, float qy, float qz,
    float *roll, float *pitch, float *yaw)
{
    /* roll (rotacija oko X-ose) */
    float sinr = 2.0f * (qw*qx + qy*qz);
    float cosr = 1.0f - 2.0f * (qx*qx + qy*qy);
    *roll  = atan2f(sinr, cosr) * RAD2DEG;

    /* pitch (rotacija oko Y-ose) */
    float sinp = 2.0f * (qw*qy - qz*qx);
    if (sinp >  1.0f) sinp =  1.0f;
    if (sinp < -1.0f) sinp = -1.0f;
    *pitch = asinf(sinp) * RAD2DEG;

    /* yaw (rotacija oko Z-ose) */
    float siny = 2.0f * (qw*qz + qx*qy);
    float cosy = 1.0f - 2.0f * (qy*qy + qz*qz);
    *yaw   = atan2f(siny, cosy) * RAD2DEG;
}

/* ---------- Main ---------- */
int main(void) {

    /* HW stanje */
    float qw = 1.0f, qx = 0.0f, qy = 0.0f, qz = 0.0f;

    /* Ramp gain */
    float rampedGain = 10.0f;
    bool  initialising = true;
    const float gain           = 0.5f;
    const float rampedGainStep = (10.0f - 0.5f) / 3.0f;
    const float dt             = 1.0f / (float)SAMPLE_RATE;

    int timeout_count = 0;

    xil_printf("\r\n");
    xil_printf("# AHRS HW trajektorija (puni dataset, %d sample-ova)\r\n", N_SAMPLES);
    xil_printf("# Capture sve izmedju BEGIN_CSV i END_CSV u CSV fajl\r\n");
    xil_printf("BEGIN_CSV\r\n");
    xil_printf("time,qw,qx,qy,qz,roll,pitch,yaw,hfbx,hfby,hfbz,ax,ay,az,hgx,hgy,hgz\r\n");

    for (int i = 0; i < N_SAMPLES; i++) {
        const SensorSample *s = &SAMPLES[i];

        const float hgx = qx * qz - qw * qy;
        const float hgy = qy * qz + qw * qx;
        const float hgz = qw * qw - 0.5f + qz * qz;

        if (initialising) {
            rampedGain -= rampedGainStep * dt;
            if (rampedGain < gain) {
                rampedGain   = gain;
                initialising = false;
            }
        }

        float nqw, nqx, nqy, nqz;
        float hfbx_hw, hfby_hw, hfbz_hw;
        int rc = hw_sec5to8(qw, qx, qy, qz,
                                    s->gx, s->gy, s->gz,
                                    s->ax, s->ay, s->az,
                                    hgx, hgy, hgz,
                                    dt, rampedGain,
                                    &nqw, &nqx, &nqy, &nqz,
                                    &hfbx_hw, &hfby_hw, &hfbz_hw);
                if (rc != 0) {
                    timeout_count++;
                    nqw = qw; nqx = qx; nqy = qy; nqz = qz;
                    hfbx_hw = 0; hfby_hw = 0; hfbz_hw = 0;
                }

        /* Normalizuj */
        float mag2 = nqw*nqw + nqx*nqx + nqy*nqy + nqz*nqz;
        float inv  = (mag2 > 0.0f) ? fast_inv_sqrt(mag2) : 1.0f;
        qw = nqw * inv;
        qx = nqx * inv;
        qy = nqy * inv;
        qz = nqz * inv;

        /* Euler uglovi za vizualizaciju */
        float roll, pitch, yaw;
        quat_to_euler_deg(qw, qx, qy, qz, &roll, &pitch, &yaw);

        /* CSV red */
        pf(s->time); xil_printf(",");
        pf(qw); xil_printf(",");
        pf(qx); xil_printf(",");
        pf(qy); xil_printf(",");
        pf(qz); xil_printf(",");
        pf(roll); xil_printf(",");
        pf(pitch); xil_printf(",");
        pf(yaw); xil_printf(",");
        pf(hfbx_hw); xil_printf(",");
        pf(hfby_hw); xil_printf(",");
        pf(hfbz_hw); xil_printf(",");
        pf(s->ax); xil_printf(",");
        pf(s->ay); xil_printf(",");
        pf(s->az); xil_printf(",");
        pf(hgx); xil_printf(",");
        pf(hgy); xil_printf(",");
        pf(hgz); xil_printf("\r\n");
    }

    xil_printf("END_CSV\r\n");
    xil_printf("# Obradjeno %d sample-ova, HW timeout-ova: %d\r\n",
               N_SAMPLES, timeout_count);
    xil_printf("# Kraj.\r\n");

    return 0;
}

